import{_ as d,o as a,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"랜덤 이미지 API와 공개 갤러리","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Other/random-image-api-and-public-gallery.md","filePath":"ko-KR/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"ko-KR/Other/random-image-api-and-public-gallery.md"};function s(c,t,i,p,n,l){return a(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="랜덤-이미지-api와-공개-갤러리" tabindex="-1">랜덤 이미지 API와 공개 갤러리 <a class="header-anchor" href="#랜덤-이미지-api와-공개-갤러리" aria-label="Permalink to &quot;랜덤 이미지 API와 공개 갤러리&quot;">​</a></h1><p>두 기능은 모두 다음 위치에서 설정합니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>시스템 설정 -&gt; 기타 설정</span></span></code></pre></div><h2 id="랜덤-이미지-api" tabindex="-1">랜덤 이미지 API <a class="header-anchor" href="#랜덤-이미지-api" aria-label="Permalink to &quot;랜덤 이미지 API&quot;">​</a></h2><p>랜덤 이미지 API는 지정한 디렉터리에서 파일 하나를 무작위로 골라 반환합니다. 사이트 배경, 프로필 이미지 로테이션, 외부 페이지의 랜덤 이미지 호출에 사용할 수 있습니다.</p><p>사용하면 다음 주소를 호출할 수 있습니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://내도메인/random</span></span></code></pre></div><h2 id="api-설정" tabindex="-1">API 설정 <a class="header-anchor" href="#api-설정" aria-label="Permalink to &quot;API 설정&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>사용</td><td><code>/random</code> 인터페이스를 켜거나 끕니다. 꺼져 있으면 접근이 거부됩니다</td></tr><tr><td>디렉터리</td><td>랜덤 대상이 될 수 있는 디렉터리를 제한합니다</td></tr><tr><td>호출 예시</td><td>바로 복사해 쓸 수 있는 랜덤 이미지 API 링크를 만듭니다</td></tr></tbody></table><p>디렉터리는 여러 개 선택할 수 있습니다. 예를 들어 <code>/landscape/</code>와 <code>/portrait/</code>만 허용하면 이 두 디렉터리와 그 하위 디렉터리에서만 파일을 고릅니다.</p><h2 id="주요-파라미터" tabindex="-1">주요 파라미터 <a class="header-anchor" href="#주요-파라미터" aria-label="Permalink to &quot;주요 파라미터&quot;">​</a></h2><table tabindex="0"><thead><tr><th>파라미터</th><th>예시</th><th>설명</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>랜덤 대상 디렉터리</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td><code>image</code>, <code>video</code>, <code>audio</code> 또는 쉼표 조합</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td><code>portrait</code>, <code>landscape</code>, <code>auto</code></td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>비우면 리다이렉트, <code>url</code>은 텍스트 링크, <code>json</code>은 JSON</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td><code>type=url</code>과 함께 사용해 전체 URL 반환</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>연령 등급 필터</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>지정 태그가 포함된 파일만 선택</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>지정 태그가 포함된 파일 제외</td></tr></tbody></table><h2 id="반환-방식" tabindex="-1">반환 방식 <a class="header-anchor" href="#반환-방식" aria-label="Permalink to &quot;반환 방식&quot;">​</a></h2><p><code>type</code>을 지정하지 않으면 무작위 파일 주소로 바로 이동합니다.</p><p><code>type=url</code>은 텍스트 링크를 반환합니다.</p><p><code>type=json</code>은 파일 링크, 파일 ID, 파일명, 파일 형식, 태그, 등급 같은 정보를 반환합니다.</p><h2 id="접근-제한" tabindex="-1">접근 제한 <a class="header-anchor" href="#접근-제한" aria-label="Permalink to &quot;접근 제한&quot;">​</a></h2><p>랜덤 이미지 API는 관리자 화면의 공개 접근 규칙을 따릅니다.</p><table tabindex="0"><thead><tr><th>규칙</th><th>효과</th></tr></thead><tbody><tr><td>디렉터리 제한</td><td>허용된 디렉터리 안의 파일만 선택</td></tr><tr><td>블랙리스트</td><td>블랙리스트 파일은 후보에서 제외</td></tr><tr><td>화이트리스트 모드</td><td>공개 허용된 파일만 반환</td></tr><tr><td>연령 등급</td><td>현재 접근 모드에 따라 R12, R16, R18 등을 필터링</td></tr></tbody></table><p>조건에 맞는 파일이 없으면 매칭 결과가 없다는 응답을 반환합니다.</p><h2 id="공개-갤러리" tabindex="-1">공개 갤러리 <a class="header-anchor" href="#공개-갤러리" aria-label="Permalink to &quot;공개 갤러리&quot;">​</a></h2><p>공개 갤러리는 방문자가 허용된 디렉터리를 읽기 전용으로 둘러볼 수 있는 페이지입니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://내도메인/browse/디렉터리명</span></span></code></pre></div><h2 id="공개-갤러리-설정" tabindex="-1">공개 갤러리 설정 <a class="header-anchor" href="#공개-갤러리-설정" aria-label="Permalink to &quot;공개 갤러리 설정&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>사용</td><td>공개 갤러리를 켜거나 끕니다</td></tr><tr><td>이미지 로딩 모드</td><td>원본 이미지 또는 썸네일 사용 여부를 정합니다</td></tr><tr><td>공개 디렉터리</td><td>방문자가 접근할 수 있는 디렉터리를 지정합니다</td></tr></tbody></table><p>예를 들어 다음처럼 입력하면:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>방문자는 다음 주소에 접근할 수 있습니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://내도메인/browse/1</span></span>
<span class="line"><span>https://내도메인/browse/2</span></span>
<span class="line"><span>https://내도메인/browse/landscape</span></span>
<span class="line"><span>https://내도메인/browse/portrait</span></span></code></pre></div><p>공개하지 않은 디렉터리는 접근이 거부됩니다.</p><h2 id="갤러리-기능" tabindex="-1">갤러리 기능 <a class="header-anchor" href="#갤러리-기능" aria-label="Permalink to &quot;갤러리 기능&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기능</th><th>설명</th></tr></thead><tbody><tr><td>디렉터리 탐색</td><td>공개 디렉터리 안의 파일과 하위 디렉터리를 확인</td></tr><tr><td>검색</td><td>파일명, 파일 ID, 태그로 검색</td></tr><tr><td>형식 필터</td><td>이미지, 동영상, 오디오, 기타 파일로 필터링</td></tr><tr><td>태그 필터</td><td>지정 태그 포함 또는 제외</td></tr><tr><td>방향 필터</td><td>가로형, 세로형 등으로 필터링</td></tr><tr><td>링크 복사</td><td>파일 접근 링크 복사</td></tr><tr><td>미디어 미리보기</td><td>이미지, 동영상, 오디오를 페이지에서 확인</td></tr></tbody></table>`,32)])])}const u=d(r,[["render",s]]);export{b as __pageData,u as default};
